import akka.actor.ActorSystem
import akka.http.scaladsl.Http
import akka.http.scaladsl.model._
import akka.http.scaladsl.server.Directives._
import akka.http.scaladsl.server.Route
import akka.http.scaladsl.marshallers.sprayjson.SprayJsonSupport._
import spray.json._

import scala.xml._
import scala.collection.mutable
import scala.concurrent.ExecutionContextExecutor
import javax.xml.parsers.SAXParserFactory

case class ConfigSetting(key: String, value: String, section: Option[String] = None)
case class ParsedConfig(settings: List[ConfigSetting], sections: List[String], rawXml: String)
case class ParseRequest(xml: String)
case class ParseResponse(success: Boolean, config: Option[ParsedConfig] = None, error: Option[String] = None)

object JsonProtocol extends DefaultJsonProtocol {
  implicit val configSettingFormat: RootJsonFormat[ConfigSetting] = jsonFormat3(ConfigSetting)
  implicit val parsedConfigFormat: RootJsonFormat[ParsedConfig] = jsonFormat3(ParsedConfig)
  implicit val parseRequestFormat: RootJsonFormat[ParseRequest] = jsonFormat1(ParseRequest)
  implicit val parseResponseFormat: RootJsonFormat[ParseResponse] = jsonFormat3(ParseResponse)
}

object ConfigXmlParser {

  private def createSafeParser(): SAXParser = {
    val factory = SAXParserFactory.newInstance()
    // Disable external entities to prevent XXE attacks
    factory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true)
    factory.setFeature("http://xml.org/sax/features/external-general-entities", false)
    factory.setFeature("http://xml.org/sax/features/external-parameter-entities", false)
    factory.setFeature("http://apache.org/xml/features/nonvalidating/load-external-dtd", false)
    factory.setXIncludeAware(false)
    factory.newSAXParser()
  }

  def parseConfig(xmlString: String): ParsedConfig = {
    val safeParser = createSafeParser()
    val xml = XML.withSAXParser(safeParser).loadString(xmlString)

    val settings = mutable.ListBuffer[ConfigSetting]()
    val sections = mutable.ListBuffer[String]()

    extractSettings(xml, None, settings, sections)

    ParsedConfig(
      settings = settings.toList,
      sections = sections.distinct.toList,
      rawXml = xmlString
    )
  }

  private def extractSettings(
    node: Node,
    currentSection: Option[String],
    settings: mutable.ListBuffer[ConfigSetting],
    sections: mutable.ListBuffer[String]
  ): Unit = {
    node match {
      case elem: Elem =>
        elem.label match {
          case "configuration" | "config" =>
            elem.child.foreach(child => extractSettings(child, currentSection, settings, sections))

          case "section" | "group" =>
            val sectionName = (elem \ "@name").text match {
              case "" => (elem \ "@id").text match {
                case "" => elem.label
                case id => id
              }
              case name => name
            }
            sections += sectionName
            // Extract section-level attributes as settings
            elem.attributes.foreach { attr =>
              if (attr.key != "name" && attr.key != "id") {
                settings += ConfigSetting(
                  key = attr.key,
                  value = attr.value.text,
                  section = Some(sectionName)
                )
              }
            }
            elem.child.foreach(child => extractSettings(child, Some(sectionName), settings, sections))

          case "setting" | "property" | "param" | "entry" =>
            val key = (elem \ "@key").text match {
              case "" => (elem \ "@name").text match {
                case "" => (elem \ "@id").text
                case name => name
              }
              case key => key
            }
            val value = (elem \ "@value").text match {
              case "" => elem.text.trim
              case v => v
            }
            if (key.nonEmpty) {
              settings += ConfigSetting(
                key = key,
                value = value,
                section = currentSection
              )
            }

          case "include" =>
            val ref = (elem \ "@ref").text
            if (ref.nonEmpty) {
              settings += ConfigSetting(
                key = s"__include__$ref",
                value = ref,
                section = currentSection
              )
            }

          case other =>
            // Treat arbitrary elements as key-value pairs
            val text = elem.text.trim
            if (text.nonEmpty && elem.child.forall(_.isInstanceOf[Text])) {
              settings += ConfigSetting(
                key = other,
                value = text,
                section = currentSection
              )
            }
            // Also extract attributes as settings
            elem.attributes.foreach { attr =>
              settings += ConfigSetting(
                key = s"$other.${attr.key}",
                value = attr.value.text,
                section = currentSection
              )
            }
            // Recurse into children
            elem.child.foreach(child => extractSettings(child, currentSection, settings, sections))
        }

      case _ => // ignore text nodes, comments, etc.
    }
  }

  def getSettingsBySection(config: ParsedConfig, section: String): List[ConfigSetting] = {
    config.settings.filter(_.section.contains(section))
  }

  def getSetting(config: ParsedConfig, key: String, section: Option[String] = None): Option[ConfigSetting] = {
    config.settings.find { s =>
      s.key == key && (section.isEmpty || s.section == section)
    }
  }

  def resolveReferences(config: ParsedConfig): ParsedConfig = {
    val settingsMap = config.settings
      .filterNot(_.key.startsWith("__include__"))
      .map(s => {
        val fullKey = s.section.map(sec => s"$sec.${s.key}").getOrElse(s.key)
        fullKey -> s.value
      })
      .toMap

    val resolvedSettings = config.settings.map { setting =>
      val resolvedValue = resolveValue(setting.value, settingsMap)
      setting.copy(value = resolvedValue)
    }

    config.copy(settings = resolvedSettings)
  }

  private def resolveValue(value: String, settingsMap: Map[String, String]): String = {
    val pattern = """\$\{([^}]+)\}""".r
    var resolved = value
    var iterations = 0
    val maxIterations = 10 // prevent infinite recursion

    while (pattern.findFirstIn(resolved).isDefined && iterations < maxIterations) {
      resolved = pattern.replaceAllIn(resolved, m => {
        val ref = m.group(1)
        java.util.regex.Matcher.quoteReplacement(settingsMap.getOrElse(ref, m.matched))
      })
      iterations += 1
    }
    resolved
  }
}

object ConfigManagementService extends App {
  import JsonProtocol._

  implicit val system: ActorSystem = ActorSystem("config-management")
  implicit val executionContext: ExecutionContextExecutor = system.dispatcher

  val configStore = mutable.Map[String, ParsedConfig]()

  val route: Route = pathPrefix("api" / "config") {
    concat(
      // Parse XML configuration
      path("parse") {
        post {
          entity(as[ParseRequest]) { request =>
            try {
              val config = ConfigXmlParser.parseConfig(request.xml)
              val resolved = ConfigXmlParser.resolveReferences(config)
              complete(StatusCodes.OK, ParseResponse(success = true, config = Some(resolved)))
            } catch {
              case e: org.xml.sax.SAXParseException =>
                complete(StatusCodes.BadRequest, ParseResponse(
                  success = false,
                  error = Some(s"XML parsing error: ${e.getMessage}")
                ))
              case e: Exception =>
                complete(StatusCodes.InternalServerError, ParseResponse(
                  success = false,
                  error = Some(s"Error processing configuration: ${e.getMessage}")
                ))
            }
          }
        }
      },
      // Store a named configuration
      path("store" / Segment) { name =>
        post {
          entity(as[ParseRequest]) { request =>
            try {
              val config = ConfigXmlParser.parseConfig(request.xml)
              val resolved = ConfigXmlParser.resolveReferences(config)
              configStore.put(name, resolved)
              complete(StatusCodes.OK, ParseResponse(success = true, config = Some(resolved)))
            } catch {
              case e: Exception =>
                complete(StatusCodes.BadRequest, ParseResponse(
                  success = false,
                  error = Some(s"Error: ${e.getMessage}")
                ))
            }
          }
        }
      },
      // Retrieve a stored configuration
      path("retrieve" / Segment) { name =>
        get {
          configStore.get(name) match {
            case Some(config) =>
              complete(StatusCodes.OK, ParseResponse(success = true, config = Some(config)))
            case None =>
              complete(StatusCodes.NotFound, ParseResponse(
                success = false,
                error = Some(s"Configuration '$name' not found")
              ))
          }
        }
      },
      // Get a specific setting from a stored configuration
      path("setting" / Segment / Segment) { (configName, settingKey) =>
        get {
          parameter("section".optional) { section =>
            configStore.get(configName) match {
              case Some(config) =>
                ConfigXmlParser.getSetting(config, settingKey, section) match {
                  case Some(setting) =>
                    complete(StatusCodes.OK, setting)
                  case None =>
                    complete(StatusCodes.NotFound, ParseResponse(
                      success = false,
                      error = Some(s"Setting '$settingKey' not found in configuration '$configName'")
                    ))
                }
              case None =>
                complete(StatusCodes.NotFound, ParseResponse(
                  success = false,
                  error = Some(s"Configuration '$configName' not found")
                ))
            }
          }
        }
      },
      // Get all settings in a section
      path("section" / Segment / Segment) { (configName, sectionName) =>
        get {
          configStore.get(configName) match {
            case Some(config) =>
              val sectionSettings = ConfigXmlParser.getSettingsBySection(config, sectionName)
              complete(StatusCodes.OK, sectionSettings)
            case None =>
              complete(StatusCodes.NotFound, ParseResponse(
                success = false,
                error = Some(s"Configuration '$configName' not found")
              ))
          }
        }
      },
      // List all stored configurations
      path("list") {
        get {
          complete(StatusCodes.OK, configStore.keys.toList.toJson)
        }
      },
      // Delete a stored configuration
      path("delete" / Segment) { name =>
        delete {
          configStore.remove(name) match {
            case Some(_) =>
              complete(StatusCodes.OK, ParseResponse(success = true))
            case None =>
              complete(StatusCodes.NotFound, ParseResponse(
                success = false,
                error = Some(s"Configuration '$name' not found")
              ))
          }
        }
      },
      // Validate XML configuration without storing
      path("validate") {
        post {
          entity(as[ParseRequest]) { request =>
            try {
              ConfigXmlParser.parseConfig(request.xml)
              complete(StatusCodes.OK, ParseResponse(success = true))
            } catch {
              case e: Exception =>
                complete(StatusCodes.BadRequest, ParseResponse(
                  success = false,
                  error = Some(s"Validation failed: ${e.getMessage}")
                ))
            }
          }
        }
      }
    )
  }

  val bindingFuture = Http().newServerAt("0.0.0.0", 8080).bind(route)

  println("Configuration Management Service running at http://0.0.0.0:8080/")
  println("Endpoints:")
  println("  POST   /api/config/parse              - Parse XML configuration")
  println("  POST   /api/config/store/{name}        - Store a named configuration")
  println("  GET    /api/config/retrieve/{name}     - Retrieve a stored configuration")
  println("  GET    /api/config/setting/{name}/{key} - Get a specific setting")
  println("  GET    /api/config/section/{name}/{sec} - Get all settings in a section")
  println("  GET    /api/config/list                - List all stored configurations")
  println("  DELETE /api/config/delete/{name}       - Delete a stored configuration")
  println("  POST   /api/config/validate            - Validate XML configuration")
}